import path from 'node:path';
import { getCountriesData } from 'frontend-country_config';
import { readLibTranslationDirs, readTranslationsDirs, readMessagesFile } from './fs.mjs';

function createCountriesLocales() {
    return new Map(Object.values(getCountriesData()).map(({ id, locale }) => [
        id,
        locale.replace('_', '-'),
    ]));
}
function createTranslations(srcPath) {
    const translations = new Map();
    const translationDirs = readLibTranslationDirs();
    // Add app translations dir
    translationDirs.push(path.join(srcPath, 'translations'));
    translationDirs
        .flatMap((dir) => readTranslationsDirs(dir))
        .forEach((dirPath) => {
        if (!dirPath) {
            return;
        }
        const locale = path.basename(dirPath);
        translations.set(locale, Object.assign(translations.get(locale) ?? {}, readMessagesFile(dirPath) ?? {}));
    });
    translations.forEach((value, key) => {
        translations.set(key, Object.freeze(value));
    });
    return translations;
}

export { createCountriesLocales, createTranslations };
